export const LOCATIONS_BY_ID = Object.fromEntries(LOCATIONS.map(l => [l.id, l]));

export const LOCATIONS_BY_SYSTEM = LOCATIONS.reduce((acc, l) => {
  if (!acc[l.system]) acc[l.system] = [];
  acc[l.system].push(l);
  return acc;
}, {});

export const LOCATIONS_BY_BODY = LOCATIONS.reduce((acc, l) => {
  if (!acc[l.body]) acc[l.body] = [];
  acc[l.body].push(l);
  return acc;
}, {});

export const LOCATIONS_BY_TYPE = LOCATIONS.reduce((acc, l) => {
  if (!acc[l.type]) acc[l.type] = [];
  acc[l.type].push(l);
  return acc;
}, {});

export const CAVE_LOCATIONS = LOCATIONS.filter(l => l.type === 'cave');
export const COMBAT_LOCATIONS = LOCATIONS.filter(l => l.subtype === 'combat');
export const ILLEGAL_LOCATIONS = LOCATIONS.filter(l => !l.legal);

